<template>
  <div class="dashboard">
    <el-card class="welcome-card">
      <h2>👋 欢迎回来，管理员</h2>
      <p class="subtitle">记录生活，留给未来。这是你的创作空间。</p>
    </el-card>

    <el-row :gutter="20" class="stats-row">
      <el-col :span="8">
        <el-card shadow="hover" class="stat-card">
          <div class="stat-content">
            <div class="icon-wrapper blue"><el-icon :size="30"><Document /></el-icon></div>
            <div class="stat-info">
              <div class="count">{{ stats.total }}</div>
              <div class="label">文章总数</div>
            </div>
          </div>
        </el-card>
      </el-col>
      <el-col :span="8">
        <el-card shadow="hover" class="stat-card">
          <div class="stat-content">
            <div class="icon-wrapper green"><el-icon :size="30"><CircleCheck /></el-icon></div>
            <div class="stat-info">
              <div class="count">{{ stats.published }}</div>
              <div class="label">已发布</div>
            </div>
          </div>
        </el-card>
      </el-col>
      <el-col :span="8">
        <el-card shadow="hover" class="stat-card">
          <div class="stat-content">
            <div class="icon-wrapper orange"><el-icon :size="30"><EditPen /></el-icon></div>
            <div class="stat-info">
              <div class="count">{{ stats.drafts }}</div>
              <div class="label">草稿箱</div>
            </div>
          </div>
        </el-card>
      </el-col>
    </el-row>

    <el-card class="quick-actions" style="margin-top: 20px;">
      <template #header>
        <div class="card-header">
          <span>快捷操作</span>
        </div>
      </template>
      <el-button type="primary" @click="$router.push('/articles/create')">
        <el-icon><Plus /></el-icon> 新建文章
      </el-button>
      <el-button type="success" plain @click="$router.push('/articles')">
        <el-icon><List /></el-icon> 管理文章
      </el-button>
    </el-card>
  </div>
</template>

<script setup>
import { ref, onMounted } from 'vue';
import { Document, CircleCheck, EditPen, Plus, List } from '@element-plus/icons-vue';
import request from '../api/request';

const stats = ref({ total: 0, published: 0, drafts: 0 });

onMounted(async () => {
  try {
    const res = await request.get('/articles');
    if (res.success) {
      const articles = res.data || [];
      stats.value.total = articles.length;
      stats.value.published = articles.filter(a => a.status === 'published').length;
      stats.value.drafts = articles.filter(a => a.status === 'draft').length;
    }
  } catch (e) {
    console.error(e);
  }
});
</script>

